/**
 * @param {string} lStr
 * @param {string} rStr
 * @param {string} directions
 * @return {number}
 */
function solve(lStr, rStr, directions) {
    const l = BigInt(lStr);
    const r = BigInt(rStr);
    let goodCount = 0;

    /**
     * Processes a single number x and checks if it is a "good" integer.
     * @param {bigint} x
     * @param {string} directions
     * @returns {boolean} True if x is a good integer, false otherwise.
     */
    const isGood = (x, directions) => {
        // 1. Format x to a 16-digit string with leading zeros
        let xStr = x.toString();
        while (xStr.length < 16) {
            xStr = "0" + xStr;
        }

        // 2. Populate the 4x4 grid
        const grid = Array(4).fill(0).map(() => Array(4).fill(0));
        let k = 0;
        for (let i = 0; i < 16; i++) {
            // The digit is the numeric value of the character at xStr[i]
            const digit = parseInt(xStr[i], 10);
            const row = Math.floor(k / 4);
            const col = k % 4;
            grid[row][col] = digit;
            k++;
        }

        // 3. Traverse the grid according to directions
        let row = 0;
        let col = 0;
        const pathSequence = [grid[row][col]]; // Start at (0, 0)

        for (let i = 0; i < directions.length; i++) {
            const dir = directions[i];

            if (dir === 'D') {
                row += 1;
            } else if (dir === 'R') {
                col += 1;
            }

            // Check for boundary conditions (although the problem context implies the path stays within 4x4)
            // Given the constraints (3 'D', 3 'R'), the max row reached is 3, max col is 3.
            // (0,0) -> D(1,0) -> D(2,0) -> D(3,0) -> R(3,1) -> R(3,2) -> R(3,3). This is safe.

            // Record the visited cell's value
            pathSequence.push(grid[row][col]);
        }

        // The path sequence generated has 7 elements (1 initial + 6 steps)
        // 4x4 grid traversal with 6 steps = 1 initial + 6 steps = 7 elements.
        if (pathSequence.length !== 7) {
            // Should not happen based on problem description
            return false;
        }


        // 4. Check if the sequence is non-decreasing
        for (let i = 0; i < 6; i++) {
            if (pathSequence[i] > pathSequence[i + 1]) {
                return false; // Not non-decreasing
            }
        }

        return true; // Is non-decreasing
    };

    // Iterate from L to R
    let current = l;
    while (current <= r) {
        if (isGood(current, directions)) {
            goodCount++;
        }
        current += 1n;
    }

    return goodCount;
}

